#include <vector>
#include <algorithm>

long long solve(std::vector<long long> nums, long long k) {
    if (nums.size() == 1) {
        return 0;
    }

    std::sort(nums.begin(), nums.end());
    long long n = nums.size();
    long long min_remove = n;  // Maximum possible removals

    for (long long i = 0; i < n; ++i) {
        // Consider the subarray from i to n-1
        // The minimum is nums[i], the maximum is nums[n-1]
        if (nums[n - 1] <= nums[i] * k) {
            // This subarray is balanced, so we can keep it
            // The number of elements to remove is n - i - 1
            min_remove = std::min(min_remove, n - i - 1);
        }
    }

    return min_remove;
}
